for name, g in galaxies.items():
    r = np.array(g['r'])
    vobs = np.array(g['vobs'])
    vgas = np.array(g['vgas'])
    vdisk = np.array(g['vdisk'])
    vbul = np.array(g['vbul'])
    
    vbar = np.sqrt(vgas**2 + (ML*vdisk)**2 + (ML*vbul)**2)
    vdm_sq = vobs**2 - vbar**2
    vdm = np.where(vdm_sq > 0, np.sqrt(vdm_sq), 0)
    
    r_norm = r / r.max()
    v_norm = vdm / max(vdm.max(), 1e-10)
    
    fname = f"data/sparc_{name.lower()}.csv"
    with open(fname, 'w') as f:
        f.write('z_real,z_imag,target_real,target_imag\n')
        for ri, vi in zip(r_norm, v_norm):
            f.write(f'{ri},0.0,{vi},0.0\n')
    
    print(f"{name:12s}: {len(r):3d} pts -> {fname}")

print(f"\n{len(galaxies)} galaxies ready")
